import{_ as a,o as e,c as i,a2 as s}from"./chunks/framework.BKchhTkY.js";const k=JSON.parse('{"title":"BetaRobot 项目介绍","description":"","frontmatter":{},"headers":[],"relativePath":"guide/intro.md","filePath":"guide/intro.md","lastUpdated":1783672098000}'),r={name:"guide/intro.md"};function d(n,t,l,h,o,p){return e(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="betarobot-项目介绍" tabindex="-1">BetaRobot 项目介绍 <a class="header-anchor" href="#betarobot-项目介绍" aria-label="Permalink to &quot;BetaRobot 项目介绍&quot;">​</a></h1><h2 id="项目概述" tabindex="-1">项目概述 <a class="header-anchor" href="#项目概述" aria-label="Permalink to &quot;项目概述&quot;">​</a></h2><p>BetaRobot 是一个基于 STM32 的嵌入式机器人控制框架，支持多开发板、多 Application 并行开发。</p><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to &quot;特点&quot;">​</a></h3><ol><li><strong>多开发板支持</strong> — 通过一个宏定义即可切换开发板（STM32F407VET6 / DM-MC02 / DJI A / DJI C）</li><li><strong>多 App 支持</strong> — 多个 Application 可同时开发，底层更新时所有使用者可直接更新</li><li><strong>静态内存分配</strong> — 所有内存静态分配，无动态内存管理，适合实时嵌入式系统</li><li><strong>分层架构</strong> — BSP/DRV/APP 三层分离，单向依赖</li><li><strong>开源透明</strong> — 底层实现完全可见，便于理解和调试</li></ol><h3 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 复制配置文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user_cfg.h.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user_cfg.h</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 构建项目（使用 CMake）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ..</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span></code></pre></div><h3 id="开发板支持" tabindex="-1">开发板支持 <a class="header-anchor" href="#开发板支持" aria-label="Permalink to &quot;开发板支持&quot;">​</a></h3><table tabindex="0"><thead><tr><th>开发板</th><th>主控芯片</th><th>宏定义</th></tr></thead><tbody><tr><td>STM32F407VET6</td><td>STM32F407VET6</td><td><code>STM32F407VET6</code></td></tr><tr><td>DM-MC02</td><td>STM32H723xx</td><td><code>DM_MC02</code></td></tr><tr><td>DJI A</td><td>STM32F427xx</td><td><code>DJI_A</code></td></tr><tr><td>DJI C</td><td>STM32F407xx</td><td><code>DJI_C</code></td></tr></tbody></table><h3 id="分层架构速查" tabindex="-1">分层架构速查 <a class="header-anchor" href="#分层架构速查" aria-label="Permalink to &quot;分层架构速查&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>职责</th><th>关键点</th></tr></thead><tbody><tr><td>APP</td><td>业务逻辑、任务调度</td><td>唯一使用 FreeRTOS 的层，管理队列/互斥量/任务</td></tr><tr><td>DRV</td><td>模块驱动、协议解析</td><td>封装外部模块，提供解析函数，默认不使用 RTOS</td></tr><tr><td>BSP</td><td>外设封装、中断分发</td><td>管理 MCU 外设实例，回调分发，不配置硬件</td></tr></tbody></table><h3 id="仓库地址" tabindex="-1">仓库地址 <a class="header-anchor" href="#仓库地址" aria-label="Permalink to &quot;仓库地址&quot;">​</a></h3><ul><li>GitHub: <a href="https://github.com/itgz123/BetaRobot" target="_blank" rel="noreferrer">https://github.com/itgz123/BetaRobot</a></li><li>Gitee: <a href="https://gitee.com/trwwrt/BetaRobot" target="_blank" rel="noreferrer">https://gitee.com/trwwrt/BetaRobot</a></li></ul>`,13)])])}const b=a(r,[["render",d]]);export{k as __pageData,b as default};
